interviewQuestions.answer:
Use Object.create(proto): <code>const animal = { eat() { console.log('eating'); } };
const dog = Object.create(animal);
dog.eat(); // inherited</code> You can also use the 'class' syntax with 'extends', which sets up prototype chains under the hood.

Shadowing occurs when an object defines its own property with the same name as a prototype property. The own property hides (shadows) the inherited one: <code>const obj = Object.create({ x: 10 });
obj.x = 20; // shadows the prototype's x
console.log(obj.x); // 20</code> The prototype's property still exists but is no longer accessible via that object (unless using delete or Reflect).

When a function is called with new, the new object's [[Prototype]] is set to the function's .prototype property. Methods added to Constructor.prototype are shared across all instances: <code>function Person(name) { this.name = name; }
Person.prototype.greet = function() { return 'Hi ' + this.name; };
const p = new Person('Alice');
p.greet(); // 'Hi Alice'</code>

codeExamples.code:
const animal = {
  speak() { return `${this.name} makes a sound.`; },
  eat()   { return `${this.name} is eating.`; }
};

const dog = Object.create(animal);
dog.name = 'Buddy';

console.log(dog.speak()); // 'Buddy makes a sound.'
console.log(dog.eat());   // 'Buddy is eating.'
console.log(dog.hasOwnProperty('speak')); // false (inherited)

function Vehicle(type) {
  this.type = type;
  this.miles = 0;
}

Vehicle.prototype.drive = function(dist) {
  this.miles += dist;
  return `Drove ${dist} miles. Total: ${this.miles}`;
};

const car = new Vehicle('Car');
const truck = new Vehicle('Truck');

console.log(car.drive(100)); // 'Drove 100 miles. Total: 100'
console.log(truck.drive(50)); // 'Drove 50 miles. Total: 50'
console.log(car.drive === truck.drive); // true (same function)

const parent = { inherited: true };
const child = Object.create(parent);
child.own = 'mine';

console.log(child.own);        // 'mine'
console.log(child.inherited);   // true (via prototype)

console.log(child.hasOwnProperty('own'));       // true
console.log(child.hasOwnProperty('inherited')); // false

console.log('inherited' in child); // true (checks full chain)

const base = { value: 10 };
const derived = Object.create(base);

console.log(derived.value); // 10 (inherited)

derived.value = 20; // shadows the prototype property
console.log(derived.value); // 20
console.log(base.value);    // 10 (unchanged)

delete derived.value;
console.log(derived.value); // 10 (inherited again)

const grandParent = { grand: true };
const parent = Object.create(grandParent);
parent.parentProp = 'from parent';
const child = Object.create(parent);
child.childProp = 'from child';

console.log(child.childProp);       // 'from child' (own)
console.log(child.parentProp);      // 'from parent' (1 level up)
console.log(child.grand);           // true (2 levels up)
console.log(child.toString);        // function (from Object.prototype)

// Walk the chain manually:
let proto = Object.getPrototypeOf(child);
while (proto) {
  console.log(Object.keys(proto));
  proto = Object.getPrototypeOf(proto);
}
